1	import { createInngestRouteContext } from "@api/platform/inngest";
2	
3	export const { GET, POST, PUT } = createInngestRouteContext();
4

1	/**
2	 * POST /api/ingest/:provider
3	 *
4	 * Webhook ingestion endpoint for external provider webhooks.
5	 * Validates HMAC signatures and dispatches to the Inngest pipeline.
6	 *
7	 * NOT tRPC — external providers send raw HTTP with HMAC signatures.
8	 */
9	
10	import { inngest } from "@api/platform/inngest/client";
11	import { getProviderConfigs } from "@api/platform/lib/provider-configs";
12	import { db } from "@db/app/client";
13	import { gatewayWebhookDeliveries } from "@db/app/schema";
14	import type { WebhookDef } from "@repo/app-providers";
15	import {
16	  deriveVerifySignature,
17	  getProvider,
18	  hasInboundWebhooks,
19	  isWebhookProvider,
20	} from "@repo/app-providers";
21	import { parseError } from "@vendor/observability/error/next";
22	import { log } from "@vendor/observability/log/next";
23	import type { NextRequest } from "next/server";
24	
25	export const runtime = "nodejs";
26	
27	// ── Helpers ──────────────────────────────────────────────────────────────────
28	
29	/**
30	 * Resolve WebhookDef from any provider kind that supports inbound webhooks.
31	 */
32	function getWebhookDef(
33	  providerDef: NonNullable<ReturnType<typeof getProvider>>
34	): WebhookDef<unknown> | null {
35	  if (isWebhookProvider(providerDef)) {
36	    return providerDef.webhook as WebhookDef<unknown>;
37	  }
38	  if (providerDef.kind === "managed") {
39	    return providerDef.inbound.webhook as WebhookDef<unknown>;
40	  }
41	  if (
42	    providerDef.kind === "api" &&
43	    "inbound" in providerDef &&
44	    providerDef.inbound
45	  ) {
46	    return providerDef.inbound.webhook as WebhookDef<unknown>;
47	  }
48	  return null;
49	}
50	
51	// ── Route Handler ────────────────────────────────────────────────────────────
52	
53	export async function POST(
54	  req: NextRequest,
55	  { params }: { params: Promise<{ provider: string }> }
56	) {
57	  const { provider: providerSlug } = await params;
58	  const receivedAt = Date.now();
59	
60	  // Step 1: Provider guard
61	  const providerDef = getProvider(providerSlug);
62	  if (!providerDef) {
63	    return Response.json(
64	      { error: "unknown_provider", provider: providerSlug },
65	      { status: 404 }
66	    );
67	  }
68	
69	  if (!hasInboundWebhooks(providerDef)) {
70	    return Response.json(
71	      { error: "not_webhook_provider", provider: providerSlug },
72	      { status: 400 }
73	    );
74	  }
75	
76	  return handleStandardWebhook(req, providerSlug, providerDef, receivedAt);
77	}
78	
79	// ── Standard Webhook Path ────────────────────────────────────────────────────
80	
81	async function handleStandardWebhook(
82	  req: NextRequest,
83	  providerSlug: string,
84	  providerDef: NonNullable<ReturnType<typeof getProvider>>,
85	  receivedAt: number
86	): Promise<Response> {
87	  const webhookDef = getWebhookDef(providerDef);
88	  if (!webhookDef) {
89	    return Response.json(
90	      { error: "no_webhook_def", provider: providerSlug },
91	      { status: 400 }
92	    );
93	  }
94	
95	  // Step 4: Webhook header guard
96	  const headersObj: Record<string, string | undefined> = {};
97	  for (const key of Object.keys(
98	    (webhookDef.headersSchema as { shape: Record<string, unknown> }).shape
99	  )) {
100	    headersObj[key] = req.headers.get(key) ?? undefined;
101	  }
102	  const headersParsed = webhookDef.headersSchema.safeParse(headersObj);
103	  if (!headersParsed.success) {
104	    return Response.json(
105	      { error: "missing_headers", issues: headersParsed.error.issues },
106	      { status: 400 }
107	    );
108	  }
109	
110	  // Step 5: Raw body capture (MUST be req.text() — HMAC needs raw bytes)
111	  const rawBody = await req.text();
112	
113	  // Step 6: Signature verification
114	  const configs = getProviderConfigs();
115	  const providerConfig = configs[providerSlug];
116	  if (!providerConfig) {
117	    log.error("[ingest] provider config not found", {
118	      provider: providerSlug,
119	    });
120	    return Response.json(
121	      { error: "provider_not_configured", provider: providerSlug },
122	      { status: 500 }
123	    );
124	  }
125	
126	  const secret = (webhookDef.extractSecret as (config: unknown) => string)(
127	    providerConfig
128	  );
129	  const verify =
130	    webhookDef.verifySignature ??
131	    deriveVerifySignature(webhookDef.signatureScheme);
132	  const isValid = await verify(rawBody, req.headers, secret);
133	  if (!isValid) {
134	    log.warn("[ingest] signature verification failed", {
135	      provider: providerSlug,
136	    });
137	    return Response.json({ error: "signature_invalid" }, { status: 401 });
138	  }
139	
140	  // Step 7: Payload parse + metadata extraction
141	  let jsonPayload: unknown;
142	  try {
143	    jsonPayload = JSON.parse(rawBody);
144	  } catch {
145	    return Response.json({ error: "invalid_json" }, { status: 400 });
146	  }
147	
148	  let parsedPayload: unknown;
149	  try {
150	    parsedPayload = webhookDef.parsePayload(jsonPayload);
151	  } catch (err) {
152	    log.warn("[ingest] payload schema validation failed", {
153	      provider: providerSlug,
154	      error: parseError(err),
155	    });
156	    return Response.json(
157	      { error: "payload_validation_failed", provider: providerSlug },
158	      { status: 400 }
159	    );
160	  }
161	  const deliveryId = webhookDef.extractDeliveryId(req.headers, parsedPayload);
162	  const eventType = webhookDef.extractEventType(req.headers, parsedPayload);
163	  const resourceId = webhookDef.extractResourceId(parsedPayload);
164	
165	  // Persist to DB
166	  await db
167	    .insert(gatewayWebhookDeliveries)
168	    .values({
169	      provider: providerSlug,
170	      deliveryId,
171	      eventType,
172	      installationId: null,
173	      status: "received",
174	      payload: JSON.stringify(parsedPayload),
175	      receivedAt: new Date(receivedAt).toISOString(),
